import tensorflow.keras as keras

# Custom loss with hyperparameter
class WeightedMSELoss(keras.losses.Loss):
    def __init__(self, weight=1.0, name='weighted_mse'):
        super().__init__(name=name)
        self.weight = weight  # Hyperparameter

    def call(self, y_true, y_pred):
        """Loss computation"""
        mse = K.mean(K.square(y_true - y_pred), axis=-1)
        return self.weight * mse

    def get_config(self):
        """Save hyperparameters when persisting model"""
        base_config = super().get_config()
        return {
            **base_config,
            'weight': self.weight
        }

