import torch

# WRONG: log(0) returns -inf, which propagates as NaN in gradients
def wrong_log_loss(y_pred: torch.Tensor, y_true: torch.Tensor) -> torch.Tensor:
    return -(y_true * torch.log(y_pred) + (1 - y_true) * torch.log(1 - y_pred)).mean()

# CORRECT: clamp predictions to (eps, 1-eps) to avoid log(0)
def correct_log_loss(y_pred: torch.Tensor, y_true: torch.Tensor, eps: float = 1e-7) -> torch.Tensor:
    y_pred = torch.clamp(y_pred, eps, 1 - eps)
    return -(y_true * torch.log(y_pred) + (1 - y_true) * torch.log(1 - y_pred)).mean()

# Even better: use PyTorch's numerically stable built-in
import torch.nn.functional as F

def stable_bce(logits: torch.Tensor, targets: torch.Tensor) -> torch.Tensor:
    """Accepts logits (pre-sigmoid), not probabilities. Numerically stable."""
    return F.binary_cross_entropy_with_logits(logits, targets.float())

# WRONG: custom normalization loss that divides by std (can be near zero)
def wrong_correlation_loss(y_pred, y_true):
    return -((y_pred - y_pred.mean()) * (y_true - y_true.mean())).mean() / (y_pred.std() * y_true.std())

# CORRECT: add epsilon to denominator
def correct_correlation_loss(y_pred, y_true, eps=1e-8):
    vx = y_pred - y_pred.mean()
    vy = y_true - y_true.mean()
    return -(vx * vy).mean() / (vx.std() * vy.std() + eps)
